const d=$('Respond OK').first().json;
const body=(d.body&&typeof d.body==='object')?d.body:{};
const query=d.query||{};

// Detect unresolved DSM template vars (%%VAR%% or %VAR%)
const isTemplate=(v)=>!v||/^%{1,2}[A-Za-z_]+%{1,2}$/.test(v.trim());

// 1. Hostname — hardcoded in DSM webhook config, always correct
const hostname=body.hostname||body.host||'unknown-synology';

// 2. Raw fields from body
const rawEvent=body.event||body.title||body.subject||'';
const rawMessage=body.message||body.text||'';
const rawSeverity=(body.severity||body.level||'').toString();
const rawCategory=(body.category||body.type||'').toString();

// 3. query.text fallback (nl-nas01 puts actual text here)
const queryText=query.text||'';

// 4. Best available actual message
let actualMessage='';
if(!isTemplate(rawMessage)&&rawMessage.length>5){
  actualMessage=rawMessage;
}else if(queryText){
  actualMessage=queryText;
}else{
  actualMessage=rawMessage;
}

// 5. Parse event/subject when template var or missing
let event=rawEvent;
if(isTemplate(event)||!event){
  const qm=queryText.match(/^\[.*?\]\s*(.+)/);
  if(qm){
    event=qm[1].trim();
  }else if(actualMessage){
    const stripped=actualMessage.replace(/^\[.*?\]\s*/,'');
    const lines=stripped.split('\n').map(l=>l.trim()).filter(l=>l);
    const meaningful=lines.filter(l=>!/^A new system event occurred/.test(l));
    event=meaningful.length>0?meaningful[0]:lines[lines.length-1]||'DSM Alert';
  }else{
    event='DSM Alert';
  }
}

// 6. Infer severity when template var
let severity=rawSeverity.toLowerCase();
if(isTemplate(rawSeverity)||!rawSeverity){
  const ml=(actualMessage+' '+event).toLowerCase();
  if(/critical|emergency|crash|failure|degrad/.test(ml))severity='critical';
  else severity='warning';
}

// 7. Infer category when template var
let category=rawCategory;
if(isTemplate(rawCategory)||!rawCategory){
  const ml=(actualMessage+' '+event).toLowerCase();
  if(/security|risk|login|firewall/.test(ml))category='Security';
  else if(/disk|smart|volume|storage|raid/.test(ml))category='Storage';
  else if(/iscsi/.test(ml))category='iSCSI';
  else if(/network|interface|link/.test(ml))category='Network';
  else if(/ups|power|battery/.test(ml))category='Power/UPS';
  else if(/backup|snapshot/.test(ml))category='Backup';
  else if(/update|dsm|package|out-of-date/.test(ml))category='Update';
  else category='System';
}

// 8. Urgency from severity + message content
const isActionable=severity!=='info';
const ml=(actualMessage+' '+event).toLowerCase();
let urgency='normal';
if(severity==='critical')urgency='critical';
else if(/i.o.latency|degraded|crashed|disk.failure|disk.error|bad.sector/.test(ml))urgency='high';
else if(/smart.+warning|ups.+(battery|power)|iscsi.+(disconnect|error)/.test(ml))urgency='high';
else if(/raid.+degrad|volume.+crash/.test(ml))urgency='critical';

// 9. Format output
const displayMsg=actualMessage.replace(/^\[.*?\]\s*/,'').replace(/\n/g,' ').trim().substring(0,300);
const em=urgency==='critical'?'\ud83d\udd34':urgency==='high'?'\ud83d\udfe0':'\ud83d\udfe1';
const pb=em+' [Synology DSM] '+event+'\nHost: '+hostname+'\nCategory: '+category+'\nSeverity: '+severity+(displayMsg&&displayMsg!==event?'\nDetails: '+displayMsg:'');
const hb='<b>'+em+' [Synology DSM] '+event+'</b><br/>Host: <code>'+hostname+'</code><br/>Category: '+category+'<br/>Severity: <code>'+severity+'</code>'+(displayMsg&&displayMsg!==event?'<br/>Details: '+displayMsg:'');
return[{json:{hostname,event,message:actualMessage,severity,category,isActionable,urgency,plainBody:pb,htmlBody:hb,matrixBody:JSON.stringify({msgtype:urgency==='normal'?'m.notice':'m.text',body:pb,format:'org.matrix.custom.html',formatted_body:hb}),safeHostname:hostname.replace(/[^a-zA-Z0-9._-]/g,''),safeEvent:event.replace(/[^a-zA-Z0-9 _-]/g,'').substring(0,50)}}];

